COMMENT ON COLUMN "turno_tarde"."fky_per" IS 'llave foranea que hace referencia a la tabla persona';
COMMENT ON COLUMN "turno_tarde"."tt_hor_lleg" IS 'campo para registrar la hora llegada en el turno de la tarde';
COMMENT ON COLUMN "turno_tarde"."tt_hor_sal" IS 'campo para registrar la hora de salida en el turno de la tarde';
COMMENT ON COLUMN "turno_tarde"."hor_tra_tt" IS 'campo para registrar las horas trabajo que tuvo el empleado en el turno de la tarde
';
COMMENT ON COLUMN "turno_tarde"."est_tt" IS 'estado del registro i: inactivo, a: activo';

